import{_ as t,o as r,c as e,ai as a}from"./chunks/framework.DMjte4z8.js";const h=JSON.parse('{"title":"触发器数组完全指南：从入门到精通","description":"","frontmatter":{"title":"触发器数组完全指南：从入门到精通","category":"triggers","updated":"2026-05-21T00:00:00.000Z","model":"openai/MiniMax-M2.7-highspeed","quality_score":0.82,"discovered_via":"gap_finder","sources":["https://www.hiveworkshop.com/threads/loops-and-arrays-tutorial.45561/","https://world-editor-tutorials.thehelper.net/cat_usersubmit.php?view=20023","https://www.youtube.com/watch?v=HpsOwfMmGO0"]},"headers":[],"relativePath":"triggers/触发器数组完全指南从入门到精通.md","filePath":"triggers/触发器数组完全指南从入门到精通.md","lastUpdated":1779353774000}'),l={name:"triggers/触发器数组完全指南从入门到精通.md"};function i(n,o,s,u,d,q){return r(),e("div",null,[...o[0]||(o[0]=[a(`<h1 id="触发器数组完全指南-从入门到精通" tabindex="-1">触发器数组完全指南：从入门到精通 <a class="header-anchor" href="#触发器数组完全指南-从入门到精通" aria-label="Permalink to “触发器数组完全指南：从入门到精通”">​</a></h1><h2 id="什么是触发器数组" tabindex="-1">什么是触发器数组 <a class="header-anchor" href="#什么是触发器数组" aria-label="Permalink to “什么是触发器数组”">​</a></h2><p>本节将介绍触发器数组的基础概念，帮助你理解为什么在制作地图时需要使用数组。完成学习后，你将掌握数组的定义、作用以及索引的工作原理。</p><h3 id="操作步骤" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤" aria-label="Permalink to “操作步骤”">​</a></h3><ol><li><strong>打开变量管理器</strong> — 在触发器编辑器顶部菜单栏点击&quot;变量&quot;按钮（显示为&quot;变量(V)&quot;）[^2]</li><li><strong>创建新变量</strong> — 点击变量窗口左下角的&quot;新建变量&quot;按钮（绿色加号图标）</li><li><strong>设置数组变量</strong> — 在弹出的变量属性窗口中，<strong>勾选&quot;数组&quot;复选框</strong>（重要！这是区分普通变量和数组变量的关键步骤）[^1]</li><li><strong>命名变量</strong> — 给数组起一个有意义的名字，比如&quot;单位生命值&quot;或&quot;玩家金币&quot;</li></ol><h3 id="数组的定义与作用" tabindex="-1">数组的定义与作用 <a class="header-anchor" href="#数组的定义与作用" aria-label="Permalink to “数组的定义与作用”">​</a></h3><p><strong>数组</strong>是什么？想象一个巨大的<strong>储物柜</strong>，上面整齐排列着许多带编号的小格子。普通变量就像一个只能放一样东西的盒子，而数组就像这个储物柜，可以同时存放多份相关的数据，每个格子都有自己专属的编号[^1]。</p><p>为什么要用数组？举个例子：假设你要追踪战场上10个单位的生命值。如果用普通变量，你需要创建&quot;血量1&quot;、&quot;血量2&quot;、&quot;血量3&quot;...一直到&quot;血量10&quot;，这太麻烦了！而使用数组，只需创建一个叫&quot;单位生命值&quot;的数组，就能通过&quot;单位生命值[1]&quot;、&quot;单位生命值[2]&quot;来访问每个单位的数据[^2]。</p><h3 id="为什么使用数组而非变量" tabindex="-1">为什么使用数组而非变量 <a class="header-anchor" href="#为什么使用数组而非变量" aria-label="Permalink to “为什么使用数组而非变量”">​</a></h3><table tabindex="0"><thead><tr><th>对比项</th><th>普通变量</th><th>数组变量</th></tr></thead><tbody><tr><td>存储数量</td><td>只能存1个</td><td>可以存8192个</td></tr><tr><td>命名方式</td><td>每个数据都要单独命名</td><td>一个名字+不同编号</td></tr><tr><td>代码效率</td><td>难以批量处理</td><td>配合循环可以批量操作</td></tr></tbody></table><p>数组的最大优势在于<strong>代码更简洁、修改更容易</strong>。当你需要调整逻辑时，只需要改一个地方，而不是找遍所有变量[^1]。</p><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常忘记勾选&quot;数组&quot;选项，导致创建的其实是普通变量。检查方法是看变量列表中该变量后面是否显示&quot;数组&quot;字样。</p></blockquote><h3 id="数组的索引-index-概念" tabindex="-1">数组的索引(Index)概念 <a class="header-anchor" href="#数组的索引-index-概念" aria-label="Permalink to “数组的索引(Index)概念”">​</a></h3><p><strong>索引（Index）</strong> 就是数组中每个格子对应的编号，用来<strong>定位你想访问的数据</strong>。关键点来了——索引从<strong>0</strong>开始计数，不是从1！这和日常生活中的编号习惯不同，很多新手会搞混[^2]。</p><ul><li><code>生命值[0]</code> → 第1个格子的数据</li><li><code>生命值[1]</code> → 第2个格子的数据</li><li><code>生命值[2]</code> → 第3个格子的数据</li><li>以此类推...</li></ul><p>在WE中，数组默认支持<strong>8192</strong>个索引位（0到8191），这个数量对于任何地图都绑绑有余了[^1]。</p><blockquote><p><strong>💡 新手提示</strong>：索引从0开始是编程世界的标准约定，记住这个规则能避免很多后续的困惑！</p></blockquote><h3 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to “小结”">​</a></h3><p>通过本节，你应该已经理解：</p><ul><li>数组是一个<strong>带编号的变量集合</strong>，能存储多个相关数据</li><li>索引从<strong>0</strong>开始，用方括号<code>[]</code>指定位置</li></ul><h2 id="创建和声明数组变量" tabindex="-1">创建和声明数组变量 <a class="header-anchor" href="#创建和声明数组变量" aria-label="Permalink to “创建和声明数组变量”">​</a></h2><p>本节将学习如何在World Editor中创建数组变量，理解全局与局部数组的区别，并掌握设置数组大小的方法。学完本节后，你将能够为自己的地图创建和管理数组变量，为后续的循环和数据存储打下基础。</p><h3 id="在变量编辑器中创建数组" tabindex="-1">在变量编辑器中创建数组 <a class="header-anchor" href="#在变量编辑器中创建数组" aria-label="Permalink to “在变量编辑器中创建数组”">​</a></h3><ol><li><p><strong>打开变量编辑器</strong> — 在World Editor工具栏中，点击&quot;触发器编辑器&quot;按钮[^1]（看起来像一个闪电符号），然后在顶部菜单选择&quot;编辑&quot;→&quot;新建变量&quot;（快捷键Ctrl+B）[^2]。</p></li><li><p><strong>输入变量名称</strong> — 在弹出的&quot;新建变量&quot;对话框中，在&quot;变量名称&quot;输入框内键入你想要的变量名，比如&quot;玩家金币&quot;或&quot;怪物计数&quot;[^2]。变量名应该清晰表达用途，方便以后阅读触发器代码。</p></li><li><p><strong>勾选&quot;数组&quot;选项</strong> — 找到&quot;数组&quot;复选框并勾选它。这一步非常关键！不勾选的话，你创建的只是普通变量，不是数组[^1]。</p></li><li><p><strong>设置数组大小</strong> — 在同一对话框中，找到&quot;数组大小&quot;选项，默认值是1[^1]。将数组大小设置为更大的数字，比如10、20或100。数组大小决定了你能存储多少个不同的值——想象一个有编号抽屉的柜子，每个编号就是一个&quot;数组索引&quot;。</p></li><li><p><strong>选择变量类型</strong> — 从下拉菜单中选择变量的数据类型，常见选项包括&quot;整数&quot;（用于计数）、&quot;实数&quot;（用于小数）、&quot;单位&quot;（用于存储游戏中的单位）、&quot;字符串&quot;（用于文本）等[^2]。</p></li><li><p><strong>确认创建</strong> — 点击&quot;确定&quot;按钮完成变量创建。你可以在变量列表中看到新创建的数组变量，旁边会有&quot;数组&quot;标记和数组大小[^1]。</p></li></ol><h3 id="全局数组与局部数组的区别" tabindex="-1">全局数组与局部数组的区别 <a class="header-anchor" href="#全局数组与局部数组的区别" aria-label="Permalink to “全局数组与局部数组的区别”">​</a></h3><ul><li><p><strong>全局数组</strong>：在变量编辑器的&quot;全局变量&quot;区域创建的数组，可以在地图的所有触发器中使用[^2]。适合存储需要跨触发器共享的数据，比如所有玩家的金币数量。</p></li><li><p><strong>局部数组</strong>：在触发器编辑器内部定义的数组，只在当前触发器执行时有效[^2]。局部数组在&quot;触发器&quot;→&quot;新建触发器&quot;→在触发器动作区域右键选择&quot;新建局部变量&quot;来创建。适合存储临时计算结果。</p></li></ul><blockquote><p><strong>💡 新手提示</strong>：作为初学者，建议先使用全局数组，因为它们更容易理解和管理。只有当你确定某个数据只需要在一个触发器内部使用时，才考虑使用局部数组。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手把数组大小设为1后，尝试使用&quot;玩家金币[1]&quot;、&quot;玩家金币[2]&quot;来存储数据，结果发现值总是覆盖同一个位置。正确的做法是：如果你需要存储5个玩家的数据，数组大小应该设为5，这样可以使用索引0到4（或者设为6，使用索引1到5）。</p></blockquote><h3 id="小结-1" tabindex="-1">小结 <a class="header-anchor" href="#小结-1" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你已经成功创建了一个数组变量。在后续的触发器中，你可以通过&quot;设置变量&quot;动作来向数组中写入数据，通过数组名加方括号内的数字（索引）来指定存储位置。例如：<code>设置 玩家金币[1] = 100</code> 表示将第一个玩家的金币设置为100。</p><h2 id="数组的基本操作" tabindex="-1">数组的基本操作 <a class="header-anchor" href="#数组的基本操作" aria-label="Permalink to “数组的基本操作”">​</a></h2><p>数组的基本操作主要分三种：赋值（Set）、读取（Get）和增减操作。学会这些后，你就能在触发器中灵活使用数组存储和管理多个数据了。</p><h3 id="操作步骤-1" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤-1" aria-label="Permalink to “操作步骤”">​</a></h3><ol><li><p><strong>第一步：创建数组变量</strong> — 在变量编辑器中新建变量时，记得把&quot;数组&quot;选项勾选上，并设置数组大小（例如32或64）[^1]。这样这个变量就变成了可以存放多个值的&quot;抽屉柜&quot;。</p></li><li><p><strong>第二步：赋值——向数组中存入数据</strong> — 在触发器中使用&quot;Set&quot;命令，选择你创建的数组变量，指定索引位置（用整数表示第几个抽屉），然后设置要存储的值[^2]。比如把&quot;玩家1的金币&quot;存入数组[1]，把&quot;玩家2的金币&quot;存入数组[2]。</p></li><li><p><strong>第三步：读取——取出数组中的数据</strong> — 要使用数组中的值时，直接在需要的地方输入&quot;变量名[索引]&quot;即可调用对应位置的数据。触发器会自动去指定的抽屉里取东西。</p></li><li><p><strong>第四步：增加和减少数组值</strong> — 对于数值类型的数组，可以使用&quot;Set&quot;命令配合数学运算。设置值为&quot;变量名[索引] + 10&quot;就相当于增加，&quot;变量名[索引] - 5&quot;就相当于减少[^2]。</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：索引从0开始！第一个位置是[0]，第二个是[1]，很多新手搞混了。如果你想存5个玩家的数据，索引应该是0到4，不是1到5。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常忘记给数组变量勾选&quot;数组&quot;选项就尝试使用索引，结果触发器报错。一定要在创建变量时检查是否正确设置了数组！</p></blockquote><h3 id="小结-2" tabindex="-1">小结 <a class="header-anchor" href="#小结-2" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你应该能创建数组变量、往里存入数据、读取数据，以及对数值进行增减操作。数组是后面学习循环的基础，一定要多练习！</p><h2 id="循环遍历数组" tabindex="-1">循环遍历数组 <a class="header-anchor" href="#循环遍历数组" aria-label="Permalink to “循环遍历数组”">​</a></h2><p>本节教你如何用循环（Loop）来<strong>自动访问数组中的每一个元素</strong>，而不是一个个手动写代码。学完后，你能实现&quot;对100个单位同时做某事&quot;这样的功能。</p><h3 id="for循环基础用法" tabindex="-1">For循环基础用法 <a class="header-anchor" href="#for循环基础用法" aria-label="Permalink to “For循环基础用法”">​</a></h3><ol><li><strong>第一步：打开触发器编辑器</strong> — 在World Editor中按F4打开触发器编辑器[^1]</li><li><strong>第二步：创建新触发器</strong> — 右键触发器列表 → 新建触发器 → 命名为&quot;遍历数组&quot;[^2]</li><li><strong>第三步：添加事件</strong> — 点击&quot;事件&quot;区域，选择地图初始化事件（Map Initialization）[^1]</li><li><strong>第四步：添加循环</strong> — 在&quot;动作&quot;中点击&quot;新建动作&quot; → 搜索&quot;For each each integer&quot;并添加[^1][^2]</li><li><strong>第五步：设置循环范围</strong> — 将循环变量的起始值设为0，终止值设为你的数组最大索引数[^2]</li><li><strong>第六步：在循环内操作</strong> — 把&quot;设置变量值&quot;或&quot;显示消息&quot;等动作拖入循环体内，使用数组变量[循环变量索引]来访问对应元素[^1]</li></ol><blockquote><p><strong>💡 新手提示</strong>：循环变量名建议改成&quot;i&quot;或&quot;index&quot;，这样代码更易读。设置方法：双击循环变量区域 → 新建局部整数变量</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：忘记把动作拖入循环体内，导致只执行一次而非对所有元素执行。检查方法：动作前面应该有&quot;为每个整数于0到X执行&quot;这个缩进的父动作[^1]</p></blockquote><h3 id="结合for-each-integer循环" tabindex="-1">结合For each integer循环 <a class="header-anchor" href="#结合for-each-integer循环" aria-label="Permalink to “结合For each integer循环”">​</a></h3><p>&quot;Foreach integer&quot;是遍历数组的最佳拍档。它的工作原理是：让一个整数从0开始，每次加1，一直加到你设定的最大值为止，每次循环都会自动执行一遍循环体内的代码[^1][^2]。</p><p>比如你有10个单位存放在UnitArray数组里，想给每个单位发送消息：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>为每个整数 i 从 0 到 9 执行</span></span>
<span class="line"><span>    - 显示 &quot;单位 [i]: (UnitArray[i]) 已就绪&quot; 给玩家</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>这样你只需写一次显示动作，系统就会自动执行10次，每次i的值分别是0、1、2...9[^1]。</p><h3 id="遍历所有数组元素的技巧" tabindex="-1">遍历所有数组元素的技巧 <a class="header-anchor" href="#遍历所有数组元素的技巧" aria-label="Permalink to “遍历所有数组元素的技巧”">​</a></h3><ol><li><strong>用变量记录实际数量</strong> — 不要写死数字，先用一个整数变量记录&quot;当前有多少个有效数据&quot;，循环就遍历到这个数为止[^2]</li><li><strong>用0值作为&quot;空&quot;的判断</strong> — 如果数组存的是整数，可以用0表示&quot;没有数据&quot;，循环内加个条件判断跳过它</li><li><strong>临时变量缓存</strong> — 循环内先把Array[i]的值赋给一个临时变量再使用，避免重复读取数组造成混乱[^1]</li></ol><blockquote><p><strong>💡 新手提示</strong>：数组索引从0开始，不是从1！UnitArray[0]是第一个元素，UnitArray[1]是第二个，这点非常重要</p></blockquote><h3 id="小结-3" tabindex="-1">小结 <a class="header-anchor" href="#小结-3" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你应该能够：</p><ul><li>✅ 创建For each integer循环结构</li><li>✅ 用循环变量作为索引访问数组元素</li><li>✅ 对数组中的所有数据进行批量操作</li></ul><p>你现在可以尝试创建一个简单的测试触发器：准备一个整数数组，循环给每个元素赋值，观察运行结果来验证是否理解正确。</p><h2 id="数组的实用案例" tabindex="-1">数组的实用案例 <a class="header-anchor" href="#数组的实用案例" aria-label="Permalink to “数组的实用案例”">​</a></h2><p>本节我们将学习数组在真实游戏中的三种经典用法。学会这些之后，你就能用数组来管理大量单位、追踪玩家数据、实现技能冷却效果——这些都是RPG地图中最常见的功能！</p><h3 id="存储多个单位信息" tabindex="-1">存储多个单位信息 <a class="header-anchor" href="#存储多个单位信息" aria-label="Permalink to “存储多个单位信息”">​</a></h3><p>假设你要做一个&quot;召唤怪物&quot;系统，玩家每次召唤一只怪物，你需要追踪最近召唤的10只怪物，以便之后可以消灭它们。</p><ol><li><p><strong>创建数组变量</strong> — 在触发器编辑器的变量列表中，点击&quot;新建变量&quot;，变量名填写 <code>召唤单位</code>，变量类型选择&quot;单位&quot;，<strong>务必勾选&quot;数组&quot;选项</strong>并将数组大小设为10[^1]</p></li><li><p><strong>设置数组元素</strong> — 创建一个&quot;单位死亡&quot;事件触发器，条件设为&quot;死亡单位持有者是触发玩家&quot;。在动作中，使用&quot;设置变量&quot;，目标<code>召唤单位[触发玩家持有者编号]</code>为&quot;死亡单位&quot;</p></li><li><p><strong>读取数组数据</strong> — 创建一个计时器周期触发器，遍历所有数组元素，检查每只召唤单位是否存在，如果存在则执行某些操作（如移动、攻击等）</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：数组索引从0开始，不是从1开始。所以<code>召唤单位[0]</code>是第一个元素，<code>召唤单位[9]</code>是第十个元素。这点非常重要，很多新手都搞错过！</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：忘记勾选&quot;数组&quot;选项就创建变量。这样创建出来的不是数组，而是一个普通变量，只能存一个值。检查方法很简单——看变量列表中该变量后面有没有带&quot;数组&quot;标签[^2]</p></blockquote><h3 id="玩家数据管理" tabindex="-1">玩家数据管理 <a class="header-anchor" href="#玩家数据管理" aria-label="Permalink to “玩家数据管理”">​</a></h3><p>在RPG地图中，每个玩家都需要独立的数据——金币、等级、杀敌数等。数组让你能轻松管理所有玩家的独立数据。</p><ol><li><p><strong>规划数据结构</strong> — 确定你需要追踪哪些玩家数据，比如：<code>玩家金币</code>、<code>玩家等级</code>、<code>玩家杀敌数</code>。每个数据都需要创建一个带数组的变量</p></li><li><p><strong>初始化玩家数据</strong> — 创建一个&quot;游戏开始&quot;触发器，添加&quot;为每个整数A从0到11&quot;循环动作（支持最多12名玩家），在循环内设置<code>玩家金币[整数A] = 0</code>、<code>玩家等级[整数A] = 1</code></p></li><li><p><strong>读取和修改数据</strong> — 当玩家执行操作时（如捡钱），使用<code>玩家金币[触发玩家持有者编号]</code>来获取该玩家的金币值，然后进行加减运算</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：玩家编号从0到11（共12个位置），对应玩家1到玩家12。在触发器中获取当前玩家时，使用&quot;触发玩家持有者&quot;这个内置值，它返回的就是0-11的数字，可以直接作为数组索引使用[^1]</p></blockquote><h3 id="技能冷却系统" tabindex="-1">技能冷却系统 <a class="header-anchor" href="#技能冷却系统" aria-label="Permalink to “技能冷却系统”">​</a></h3><p>技能冷却是让技能不能连续无限使用的机制。你可以用数组记录每个技能何时可以使用。</p><ol><li><p><strong>创建冷却数组</strong> — 创建两个数组变量：<code>技能冷却时间</code>（实数型）和<code>技能上次使用时间</code>（实数型），数组大小设为10（假设有10个技能）</p></li><li><p><strong>检查冷却状态</strong> — 在技能触发器中，添加条件检查：<code>技能冷却时间[技能索引] ≤ 游戏时间</code>。其中&quot;游戏时间&quot;是一个内置变量，记录游戏开始以来的秒数</p></li><li><p><strong>设置冷却</strong> — 当玩家成功释放技能后，使用&quot;设置变量&quot;将<code>技能上次使用时间[技能索引] = 游戏时间</code>，然后计算<code>技能冷却时间[技能索引] = 游戏时间 + 冷却秒数</code></p></li><li><p><strong>计算剩余冷却</strong> — 如果需要显示冷却倒计时，可以用&quot;技能上次使用时间 + 冷却秒数 - 游戏时间&quot;来计算剩余秒数</p></li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：忘记更新<code>技能上次使用时间</code>。如果只在释放技能时设置冷却时间，但玩家失败使用技能时（比如魔法值不足）也设置了冷却，就会导致玩家不满。正确的做法是只在技能真正成功释放后才设置冷却时间[^2]</p></blockquote><h3 id="小结-4" tabindex="-1">小结 <a class="header-anchor" href="#小结-4" aria-label="Permalink to “小结”">​</a></h3><p>完成以上三种案例的学习后，你应该已经掌握了数组的核心应用场景：</p><ul><li>用数组索引来区分不同单位或玩家</li><li>用数组配合循环来处理批量数据</li><li>用&quot;游戏时间&quot;来计算冷却等时间相关数据</li></ul><p>建议先从&quot;玩家数据管理&quot;开始练习，因为逻辑最简单。等熟悉之后，再挑战&quot;技能冷却系统&quot;这样的综合案例。动手试试吧！</p><h2 id="常见错误与调试方法" tabindex="-1">常见错误与调试方法 <a class="header-anchor" href="#常见错误与调试方法" aria-label="Permalink to “常见错误与调试方法”">​</a></h2><p>在本节中，我们将学习使用触发器数组时最常见的错误，以及如何使用&quot;显示文本&quot;功能来调试这些问题。学完本节后，你将能够自己找出并修复数组相关的Bug。</p><h3 id="数组越界问题" tabindex="-1">数组越界问题 <a class="header-anchor" href="#数组越界问题" aria-label="Permalink to “数组越界问题”">​</a></h3><p>数组越界是指你访问的索引超出了数组的有效范围。 Warcraft III 的数组索引从 0 开始，最大为 8191[^1]。如果你的循环变量 i 变成负数或超过 8191，就会出现问题。</p><ol><li><strong>创建测试触发器</strong> — 在触发器编辑器中，右键点击&quot;新建触发器&quot;[^2]</li><li><strong>添加&quot;显示文本&quot;动作</strong> — 在触发器动作中搜索&quot;显示文本到聊天框&quot;，拖入动作区域</li><li><strong>连接字符串和变量</strong> — 在显示文本中点击&quot;点击添加代码&quot;，选择你的数组变量（如 <code>UnitArray[i]</code>）</li><li><strong>故意设置错误索引</strong> — 比如设置一个会超过 8191 的循环条件来测试</li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手以为数组可以从 1 开始计数。实际上 WC3 数组从 0 开始，所以 <code>UnitArray[0]</code> 是有效的第一个位置，<code>UnitArray[1]</code> 是第二个。如果你的循环从 1 开始但从未访问 <code>UnitArray[0]</code>，你就浪费了数组的第一个位置！</p></blockquote><blockquote><p><strong>💡 新手提示</strong>：使用 <code>Modulo</code>（取模）运算可以确保索引永远不会越界。例如 <code>UnitArray[ModuloInteger(i, 8192)]</code> 会把任何数字限制在 0-8191 之间。</p></blockquote><h3 id="数组未初始化的后果" tabindex="-1">数组未初始化的后果 <a class="header-anchor" href="#数组未初始化的后果" aria-label="Permalink to “数组未初始化的后果”">​</a></h3><p>使用一个没有被赋值过的数组元素，会读取到默认值（通常为 0 或空）。这可能导致单位创建在坐标 (0,0)，或者物品凭空消失[^1]。</p><ol><li><strong>创建布尔数组测试</strong> — 新建一个布尔类型的变量 <code>HasUpgraded</code>，记得勾选&quot;数组&quot;选项</li><li><strong>新建触发器测试未初始化</strong> — 添加显示文本，显示 <code>HasUpgraded[1]</code> 的值</li><li><strong>运行地图观察</strong> — 你会看到显示为 <code>false</code>，因为从未设置为 <code>true</code></li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常忘记在第一次使用数组元素前设置初始值。解决方法是：在使用数组前，先用&quot;设置变量&quot;动作明确赋值，即使你想设置的是 false，也要写出来表明你是故意的。</p></blockquote><h3 id="使用display-text调试数组" tabindex="-1">使用Display text调试数组 <a class="header-anchor" href="#使用display-text调试数组" aria-label="Permalink to “使用Display text调试数组”">​</a></h3><p>当你不知道数组里装了什么值时，&quot;显示文本&quot;是最简单有效的调试工具[^3]。</p><ol><li><strong>在关键位置插入显示文本</strong> — 在循环内部、条件判断前后都加上，显示当前索引 i 和数组值</li><li><strong>使用整数字符串转换</strong> — 显示文本的动作中，选择&quot;整数转为字符串&quot;，然后连接你的数组索引和值</li><li><strong>按顺序观察输出</strong> — 运行地图时，聊天框会按执行顺序显示每一轮循环的值</li><li><strong>对比预期与实际</strong> — 如果显示的值和你想象的不一样，说明某处逻辑有问题</li></ol><blockquote><p><strong>💡 新手提示</strong>：调试完成后，记得把调试用的&quot;显示文本&quot;动作删除，或者把它们放到一个可以关闭的触发器组里，避免在正式游戏中干扰玩家。</p></blockquote><h3 id="小结-5" tabindex="-1">小结 <a class="header-anchor" href="#小结-5" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你应该能够使用&quot;显示文本&quot;功能来追踪数组的实际值，识别越界访问和未初始化使用的问题。记住：<strong>调试时多显示几个值，比盲目猜测要高效得多</strong>！每次修改触发器后都重新测试一遍，确保你的数组索引始终在有效范围内（0 到 8191）。</p><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to “参考来源”">​</a></h2><p>[^1]: <a href="https://www.hiveworkshop.com/threads/loops-and-arrays-tutorial.45561/" target="_blank" rel="noreferrer">[Trigger] - Loops and Arrays tutorial - Hive Workshop</a> — accessed 2026-05-21 [^2]: <a href="https://world-editor-tutorials.thehelper.net/cat_usersubmit.php?view=20023" target="_blank" rel="noreferrer">Triggers - Variables and Arrays - World Editor Tutorials</a> — accessed 2026-05-21 [^3]: <a href="https://www.youtube.com/watch?v=HpsOwfMmGO0" target="_blank" rel="noreferrer">Warcraft 3 World Editor - Beginner guide! - YouTube</a> — accessed 2026-05-21</p>`,94)])])}const p=t(l,[["render",i]]);export{h as __pageData,p as default};
